import { z } from "zod";

const envSchema = z.object({
  DATABASE_URL: z.string().min(1),
  NEXT_PUBLIC_APP_URL: z.string().url(),
  APP_URL: z.string().url().optional(),
  CLERK_SECRET_KEY: z.string().min(1),
  NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY: z.string().min(1),
  STRIPE_SECRET_KEY: z.string().min(1),
  STRIPE_WEBHOOK_SECRET: z.string().min(1),
  STRIPE_PRICE_CORE: z.string().optional(),
  STRIPE_PRICE_GROWTH: z.string().optional(),
  STRIPE_PRICE_SCALE: z.string().optional(),
  RESEND_API_KEY: z.string().min(1),
  EMAIL_FROM: z.string().min(1),
  OPENAI_API_KEY: z.string().optional(),
  INNGEST_EVENT_KEY: z.string().optional(),
  INNGEST_SIGNING_KEY: z.string().optional(),
  PUBLISH_DUE_BATCH_SIZE: z.string().optional(),
  PUBLISH_DISPATCH_THROTTLE_MS: z.string().optional(),
  S3_REGION: z.string().min(1),
  S3_BUCKET: z.string().min(1),
  S3_ACCESS_KEY_ID: z.string().min(1),
  S3_SECRET_ACCESS_KEY: z.string().min(1),
  S3_ENDPOINT: z.string().optional(),
  S3_PUBLIC_BASE_URL: z.string().optional(),
  LINKEDIN_CLIENT_ID: z.string().min(1),
  LINKEDIN_CLIENT_SECRET: z.string().min(1),
  LINKEDIN_REDIRECT_URI: z.string().url(),
  LINKEDIN_SCOPE: z.string().min(1),
  LINKEDIN_API_TIMEOUT_MS: z.string().optional(),
  LINKEDIN_OAUTH_TIMEOUT_MS: z.string().optional(),
  LINKEDIN_PUBLISH_TIMEOUT_MS: z.string().optional(),
  TOKEN_ENCRYPTION_SECRET: z.string().min(16),
  X_CLIENT_ID: z.string().optional(),
  X_CLIENT_SECRET: z.string().optional(),
  X_REDIRECT_URI: z.string().url().optional(),
  X_SCOPE: z.string().optional(),
  META_APP_ID: z.string().optional(),
  META_APP_SECRET: z.string().optional(),
  FACEBOOK_REDIRECT_URI: z.string().url().optional(),
  FACEBOOK_SCOPE: z.string().optional(),
  INSTAGRAM_REDIRECT_URI: z.string().url().optional(),
  INSTAGRAM_SCOPE: z.string().optional(),
  INSTAGRAM_STATUS_MAX_POLLS: z.string().optional(),
  INSTAGRAM_STATUS_POLL_INTERVAL_MS: z.string().optional(),
  ALERT_WEBHOOK_URL: z.string().url().optional(),
  ALERT_EMAIL_TO: z.string().email().optional(),
  SENTRY_DSN: z.string().optional(),
  META_WEBHOOK_VERIFY_TOKEN: z.string().optional(),
  X_WEBHOOK_SECRET: z.string().optional(),
  YOUTUBE_WEBHOOK_SECRET: z.string().optional(),
  ENABLE_LIVE_USAGE_METERING: z.string().optional(),
  RECONNECT_WARNING_DAYS: z.string().optional(),
});

export const env = envSchema.parse({
  DATABASE_URL: process.env.DATABASE_URL,
  NEXT_PUBLIC_APP_URL: process.env.NEXT_PUBLIC_APP_URL,
  APP_URL: process.env.APP_URL,
  CLERK_SECRET_KEY: process.env.CLERK_SECRET_KEY,
  NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY: process.env.NEXT_PUBLIC_CLERK_PUBLISHABLE_KEY,
  STRIPE_SECRET_KEY: process.env.STRIPE_SECRET_KEY,
  STRIPE_WEBHOOK_SECRET: process.env.STRIPE_WEBHOOK_SECRET,
  STRIPE_PRICE_CORE: process.env.STRIPE_PRICE_CORE,
  STRIPE_PRICE_GROWTH: process.env.STRIPE_PRICE_GROWTH,
  STRIPE_PRICE_SCALE: process.env.STRIPE_PRICE_SCALE,
  RESEND_API_KEY: process.env.RESEND_API_KEY,
  EMAIL_FROM: process.env.EMAIL_FROM,
  OPENAI_API_KEY: process.env.OPENAI_API_KEY,
  INNGEST_EVENT_KEY: process.env.INNGEST_EVENT_KEY,
  INNGEST_SIGNING_KEY: process.env.INNGEST_SIGNING_KEY,
  PUBLISH_DUE_BATCH_SIZE: process.env.PUBLISH_DUE_BATCH_SIZE,
  PUBLISH_DISPATCH_THROTTLE_MS: process.env.PUBLISH_DISPATCH_THROTTLE_MS,
  S3_REGION: process.env.S3_REGION,
  S3_BUCKET: process.env.S3_BUCKET,
  S3_ACCESS_KEY_ID: process.env.S3_ACCESS_KEY_ID,
  S3_SECRET_ACCESS_KEY: process.env.S3_SECRET_ACCESS_KEY,
  S3_ENDPOINT: process.env.S3_ENDPOINT,
  S3_PUBLIC_BASE_URL: process.env.S3_PUBLIC_BASE_URL,
  LINKEDIN_CLIENT_ID: process.env.LINKEDIN_CLIENT_ID,
  LINKEDIN_CLIENT_SECRET: process.env.LINKEDIN_CLIENT_SECRET,
  LINKEDIN_REDIRECT_URI: process.env.LINKEDIN_REDIRECT_URI,
  LINKEDIN_SCOPE: process.env.LINKEDIN_SCOPE,
  LINKEDIN_API_TIMEOUT_MS: process.env.LINKEDIN_API_TIMEOUT_MS,
  LINKEDIN_OAUTH_TIMEOUT_MS: process.env.LINKEDIN_OAUTH_TIMEOUT_MS,
  LINKEDIN_PUBLISH_TIMEOUT_MS: process.env.LINKEDIN_PUBLISH_TIMEOUT_MS,
  TOKEN_ENCRYPTION_SECRET: process.env.TOKEN_ENCRYPTION_SECRET,
  X_CLIENT_ID: process.env.X_CLIENT_ID,
  X_CLIENT_SECRET: process.env.X_CLIENT_SECRET,
  X_REDIRECT_URI: process.env.X_REDIRECT_URI,
  X_SCOPE: process.env.X_SCOPE,
  META_APP_ID: process.env.META_APP_ID,
  META_APP_SECRET: process.env.META_APP_SECRET,
  FACEBOOK_REDIRECT_URI: process.env.FACEBOOK_REDIRECT_URI,
  FACEBOOK_SCOPE: process.env.FACEBOOK_SCOPE,
  INSTAGRAM_REDIRECT_URI: process.env.INSTAGRAM_REDIRECT_URI,
  INSTAGRAM_SCOPE: process.env.INSTAGRAM_SCOPE,
  INSTAGRAM_STATUS_MAX_POLLS: process.env.INSTAGRAM_STATUS_MAX_POLLS,
  INSTAGRAM_STATUS_POLL_INTERVAL_MS: process.env.INSTAGRAM_STATUS_POLL_INTERVAL_MS,
  ALERT_WEBHOOK_URL: process.env.ALERT_WEBHOOK_URL,
  ALERT_EMAIL_TO: process.env.ALERT_EMAIL_TO,
  SENTRY_DSN: process.env.SENTRY_DSN,
  META_WEBHOOK_VERIFY_TOKEN: process.env.META_WEBHOOK_VERIFY_TOKEN,
  X_WEBHOOK_SECRET: process.env.X_WEBHOOK_SECRET,
  YOUTUBE_WEBHOOK_SECRET: process.env.YOUTUBE_WEBHOOK_SECRET,
  ENABLE_LIVE_USAGE_METERING: process.env.ENABLE_LIVE_USAGE_METERING,
  RECONNECT_WARNING_DAYS: process.env.RECONNECT_WARNING_DAYS,
});
